def check(tool_name, args, context):
    """Check if the operation targets a protected path."""
    protected_paths = ['/', '/bin', '/usr', '/etc', '/var', '/lib', '/sbin', '/boot']

    # Extract path from args
    path = args.get('path', args.get('cmd', ''))

    # Check for rm -rf patterns
    if 'rm' in str(args) and '-rf' in str(args):
        for p in protected_paths:
            if p in str(args):
                return False, f"Blocked: Attempting to delete protected path {p}"

    # Direct path check
    if isinstance(path, str):
        for p in protected_paths:
            if path == p or path.startswith(p + '/'):
                # Allow subdirectories like /tmp, /home
                if path.startswith('/tmp') or path.startswith('/home'):
                    continue
                return False, f"Blocked: Protected system path {p}"

    return True, "Path check passed"

shell_pipe_protect.action_code:
def check(tool_name, args, context):
    """Check for dangerous pipe patterns."""
    dangerous_patterns = [
        ('curl', 'bash'), ('curl', 'sh'),
        ('wget', 'bash'), ('wget', 'sh'),
        ('curl', 'python'), ('wget', 'python'),
    ]

    cmd = args.get('cmd', args.get('command', ''))
    cmd_lower = cmd.lower()

    for source, sink in dangerous_patterns:
        if source in cmd_lower and '|' in cmd_lower and sink in cmd_lower:
            return False, f"Blocked: Dangerous pipe pattern detected ({source} | {sink})"

    return True, "Pipe check passed"

