def check(tool_name, args, context):
    """Check for sensitive data patterns."""
    import re

    sensitive_patterns = [
        (r'[A-Za-z0-9]{20,}', 'API key'),           # Long alphanumeric strings
        (r'sk-[A-Za-z0-9]{40,}', 'OpenAI API key'), # OpenAI format
        (r'AKIA[0-9A-Z]{16}', 'AWS Access Key'),    # AWS format
        (r'password\s*[=:]\s*\S+', 'Password'),  # password=xxx
        (r'secret\s*[=:]\s*\S+', 'Secret'),      # secret=xxx
    ]

    # Check all string values in args
    def check_value(v):
        if not isinstance(v, str):
            return None
        for pattern, name in sensitive_patterns:
            if re.search(pattern, v, re.IGNORECASE):
                return name
        return None

    for key, value in args.items():
        if isinstance(value, str):
            match = check_value(value)
            if match:
                return False, f"Blocked: Potential {match} detected in {key}"
        elif isinstance(value, dict):
            for k, v in value.items():
                match = check_value(str(v))
                if match:
                    return False, f"Blocked: Potential {match} detected in {key}.{k}"

    return True, "Sensitive data check passed"
